import { useState, useEffect } from "react"
import API from "../services/api"

export default function Profile() {

    const [skills, setSkills] = useState([])
    const [bio, setBio] = useState("")
    const [interests, setInterests] = useState("")
    const [savedJobs, setSavedJobs] = useState([])
    const [showProfile, setShowProfile] = useState(false)

    const [resumeScore, setResumeScore] = useState(0)
    const [quizScore, setQuizScore] = useState(0)

    const skillOptions = [
        "java",
        "spring",
        "sql",
        "rest apis",
        "problem solving",
        "python",
        "react"
    ]

    const handleUpdate = async () => {

        try {

            setShowProfile(true)

            const token = localStorage.getItem("token")

            await API.put(
                "/profile/update",
                {
                    skills,
                    bio,
                    interests
                },
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            )

            alert("Profile updated")

        } catch (error) {

            console.log(error)
            alert("Update failed")
        }
    }
    

    useEffect(() => {

        const fetchProfile = async () => {

            try {

                const token = localStorage.getItem("token")

                const res = await API.get(
                    "/profile/me",
                    {
                        headers: {
                            Authorization: `Bearer ${token}`
                        }
                    }
                )

                setSkills(res.data.skills || [])
                setBio(res.data.bio || "")
                setInterests(res.data.interests || "")
                setSavedJobs(res.data.savedJobs || [])

                setResumeScore(res.data.resumeScore || 0)
                setQuizScore(res.data.quizScore || 0)

            } catch (error) {

                console.log(error)
            }
        }

        fetchProfile()

    }, [])

    const cardStyle = {
        background: "white",
        padding: "20px",
        borderRadius: "12px",
        boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
        marginBottom: "20px"
    }
    
        const handleDeleteJob = async (role) => {

    try {

        const token = localStorage.getItem("token")

        await API.delete(
            `/jobs/saved/${encodeURIComponent(role)}`,
            {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            }
        )

        setSavedJobs(
            savedJobs.filter(job => job !== role)
        )

        alert("Job removed")

    } catch (error) {

        console.log(error)

        alert("Delete failed")
    }
}
    return (

        <div
            style={{
                padding: "30px",
                background: "#f4f4f4",
                minHeight: "100vh"
            }}
        >

            <h1
                style={{
                    marginBottom: "25px"
                }}
            >
                My Profile
            </h1>

            <div style={cardStyle}>

                <h2>Update Profile</h2>

                <h4>Select Skills</h4>

                {
                    skillOptions.map((skill, index) => (

                        <label
                            key={index}
                            style={{
                                display: "block",
                                marginBottom: "8px"
                            }}
                        >

                            <input
                                type="checkbox"
                                value={skill}
                                checked={skills.includes(skill)}

                                onChange={(e) => {

                                    if (e.target.checked) {

                                        setSkills([
                                            ...skills,
                                            skill
                                        ])

                                    } else {

                                        setSkills(
                                            skills.filter(
                                                s => s !== skill
                                            )
                                        )
                                    }
                                }}
                            />

                            {" "} {skill}

                        </label>
                    ))
                }

                <br />

                <input
                    type="text"
                    value={bio}
                    placeholder="Bio"

                    onChange={(e) =>
                        setBio(e.target.value)
                    }

                    style={{
                        width: "100%",
                        padding: "10px",
                        marginBottom: "15px"
                    }}
                />

                <input
                    type="text"
                    value={interests}
                    placeholder="Interests"

                    onChange={(e) =>
                        setInterests(e.target.value)
                    }

                    style={{
                        width: "100%",
                        padding: "10px",
                        marginBottom: "15px"
                    }}
                />

                <button
                    onClick={handleUpdate}

                    style={{
                        padding: "10px 18px",
                        border: "none",
                        backgroundColor: "#4CAF50",
                        color: "white",
                        borderRadius: "8px",
                        cursor: "pointer"
                    }}
                >
                    Update Profile
                </button>

            </div>

            {
                showProfile && (

                    <div style={cardStyle}>

                        <h2>Saved Profile</h2>

                        <p>
                            <strong>Skills:</strong>{" "}
                            {skills.join(", ")}
                        </p>

                        <p>
                            <strong>Bio:</strong>{" "}
                            {bio}
                        </p>

                        <p>
                            <strong>Interests:</strong>{" "}
                            {interests}
                        </p>

                        <p>
                            <strong>ATS Score:</strong>{" "}
                            {resumeScore}
                        </p>

                        <p>
                            <strong>Quiz Score:</strong>{" "}
                            {quizScore}
                        </p>

                    </div>
                )
            }

            <div style={cardStyle}>

                <h2>Saved Jobs</h2>

                {
                    savedJobs.length > 0 ? (

                        <ul>

                            {
                                savedJobs.map((job, index) => (
                                <li
                                    key={index}
                                    style={{
                                        marginBottom: "10px",
                                        display: "flex",
                                        justifyContent: "space-between",
                                        alignItems: "center"
                                    }}
                                >
                                    <span>{job}</span>

                                    <button
                                        onClick={() => handleDeleteJob(job)}
                                        style={{
                                            background: "red",
                                            color: "white",
                                            border: "none",
                                            padding: "5px 10px",
                                            borderRadius: "5px",
                                            cursor: "pointer"
                                        }}
                                    >
                                        Delete
                                    </button>

                                </li>
                            ))
                            }

                        </ul>

                    ) : (

                        <p>No saved jobs yet</p>
                    )
                }

            </div>

        </div>
    )
}
